out vec4 fragColor;

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution;

    // Scale UV to create 8x8 tiles
    vec2 tiled = uv * 8.0;

    // Get integer tile coordinates
    vec2 tile = floor(tiled);

    // XOR parity: (tile.x + tile.y) is even -> white, odd -> black
    float checker = /* mod(tile.x + tile.y, 2.0) */;

    fragColor = vec4(checker, checker, checker, 1.0);
}

