challenges.template:
uniform vec2 u_resolution;
out vec4 fragColor;

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution;

    // Scale: 6 columns, 12 rows (bricks are wider than tall)
    vec2 tiled = uv * vec2(6.0, 12.0);

    // Determine which row we're in
    float row = floor(tiled.y);

    // Offset every other row by 0.5 in X
    tiled.x += /* 0.5 when row is odd */;

    // Local position within the tile [0,1]x[0,1]
    vec2 local = fract(tiled);

    // Draw the brick (leave a small gap at the edges for mortar)
    float mortar = 0.05;
    float brick = step(mortar, local.x) * step(mortar, local.y) *
                  step(local.x, 1.0 - mortar) * step(local.y, 1.0 - mortar);

    vec3 brickColor  = vec3(0.76, 0.3, 0.18);
    vec3 mortarColor = vec3(0.85, 0.82, 0.78);
    vec3 color = mix(mortarColor, brickColor, brick);

    fragColor = vec4(color, 1.0);
}

