challenges.template:
uniform vec2 u_resolution;
uniform float u_time;
out vec4 fragColor;

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution;

    float N = 5.0;
    vec2 tiled = uv * N;
    vec2 tile  = floor(tiled);
    vec2 local = fract(tiled) - 0.5;  // center local space at (0,0)

    // Compute per-tile phase from tile index
    float phase = /* tile.x + tile.y */;

    // Animate radius: base 0.3, oscillate by 0.15
    float radius = /* 0.3 + 0.15 * sin(u_time + phase) */;

    float d = length(local);
    float circle = smoothstep(radius + 0.02, radius - 0.02, d);

    fragColor = vec4(circle, circle * 0.5, 1.0 - circle, 1.0);
}

