challenges.template:
uniform vec2 u_resolution;
out vec4 fragColor;

vec2 hexGrid(vec2 p) {
    // Hex grid spacing
    vec2 s = vec2(1.0, sqrt(3.0));

    // Two candidate hex centers (on two interleaved rectangular grids)
    vec4 hC = floor(vec4(p, p - vec2(0.5, 1.0)) / s.xyxy) + 0.5;

    // Pick the candidate closest to p
    vec4 h  = vec4(p - hC.xy * s, p - (hC.zw + 0.5) * s);
    return dot(h.xy, h.xy) < dot(h.zw, h.zw) ? hC.xy : hC.zw + 0.5;
}

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution;
    vec2 p  = (uv - 0.5) * 8.0;  // scale to hex grid space

    // Get the hex cell center index
    vec2 id = /* hexGrid(p) */;

    // Color based on id (use fract for a repeating palette)
    vec3 color = 0.5 + 0.5 * cos(vec3(id.x + id.y, id.x, id.y) * 0.8 + vec3(0.0, 2.1, 4.2));

    fragColor = vec4(color, 1.0);
}

